mapper.select:
SELECT wo.id, wo.order_no AS orderNo, wo.order_type AS orderType, wo.address_type AS addressType, wo.community_id AS communityId, wo.reporter_name AS reporterName, wo.status, wo.repair_user_id AS repairUserId, wo.reject_count AS rejectCount, wo.urge_count AS urgeCount, wo.create_time AS createTime, wo.actual_complete_time AS actualCompleteTime, wo.repair_duration AS repairDuration FROM wo_work_order wo WHERE wo.del_flag = 0
AND wo.status = #{query.status}
AND wo.order_type = #{query.orderType}
AND wo.community_id = #{query.communityId}
AND wo.building_id = #{query.buildingId}
AND wo.create_time >= #{query.startDate}
AND wo.create_time <= #{query.endDate}
AND (wo.order_no LIKE CONCAT('%', #{query.keyword}, '%') OR wo.reporter_name LIKE CONCAT('%', #{query.keyword}, '%'))
ORDER BY wo.create_time DESC

SELECT repair_user_id AS userId, COUNT(*) AS cnt FROM wo_work_order WHERE del_flag = 0 AND status = 'IN_PROGRESS' AND repair_user_id IN
#{uid}
GROUP BY repair_user_id

SELECT status, COUNT(*) AS cnt
FROM wo_work_order
WHERE del_flag = 0

    AND community_id = #{communityId}


    AND building_id = #{buildingId}


    AND create_time >= #{startDate}


    AND create_time <= #{endDate}

GROUP BY status

SELECT CAST(AVG(repair_duration) AS SIGNED)
FROM wo_work_order
WHERE del_flag = 0
  AND status = 'COMPLETED'
  AND repair_duration IS NOT NULL

    AND community_id = #{communityId}


    AND building_id = #{buildingId}


    AND actual_complete_time >= #{startDate}


    AND actual_complete_time <= #{endDate}

SELECT AVG(e.score)
FROM wo_evaluation e
INNER JOIN wo_work_order wo ON e.order_id = wo.id AND wo.del_flag = 0
WHERE e.del_flag = 0

    AND wo.community_id = #{communityId}


    AND wo.building_id = #{buildingId}


    AND e.evaluate_time >= #{startDate}


    AND e.evaluate_time <= #{endDate}

SELECT DATE(create_time) AS date, COUNT(*) AS value
FROM wo_work_order
WHERE del_flag = 0

    AND community_id = #{communityId}


    AND building_id = #{buildingId}


    AND create_time >= #{startDate}


    AND create_time <= #{endDate}

GROUP BY DATE(create_time)
ORDER BY DATE(create_time)

SELECT DATE_FORMAT(e.evaluate_time, '%Y-%m') AS date, ROUND(AVG(e.score), 1) AS value
FROM wo_evaluation e
INNER JOIN wo_work_order wo ON e.order_id = wo.id AND wo.del_flag = 0
WHERE e.del_flag = 0

    AND wo.community_id = #{communityId}


    AND wo.building_id = #{buildingId}


    AND e.evaluate_time >= #{startDate}


    AND e.evaluate_time <= #{endDate}

GROUP BY DATE_FORMAT(e.evaluate_time, '%Y-%m')
ORDER BY DATE_FORMAT(e.evaluate_time, '%Y-%m')

SELECT wo.id, wo.order_no AS orderNo, wo.order_type AS orderType, wo.status, wo.description, wo.create_time AS createTime, wo.actual_complete_time AS actualCompleteTime, CASE WHEN wo.address_type = 'HOUSE' THEN CONCAT(bc.community_name, ' ', bb.building_name) ELSE CONCAT(bc.community_name, ' ', bb.building_name, '（公共区域）') END AS addressDesc FROM wo_work_order wo LEFT JOIN bs_community bc ON wo.community_id = bc.id LEFT JOIN bs_building bb ON wo.building_id = bb.id WHERE wo.del_flag = 0 AND wo.reporter_id = #{ownerId}
AND wo.status = #{status}
ORDER BY wo.create_time DESC

SELECT wo.id, wo.order_no AS orderNo, wo.order_type AS orderType, wo.status, wo.description, wo.create_time AS createTime, wo.actual_complete_time AS actualCompleteTime, CASE WHEN wo.address_type = 'HOUSE' THEN CONCAT(bc.community_name, ' ', bb.building_name) ELSE CONCAT(bc.community_name, ' ', bb.building_name, '（公共区域）') END AS addressDesc FROM wo_work_order wo LEFT JOIN bs_community bc ON wo.community_id = bc.id LEFT JOIN bs_building bb ON wo.building_id = bb.id WHERE wo.del_flag = 0 AND wo.repair_user_id = #{repairUserId} AND wo.status IN ('PENDING_ACCEPT', 'IN_PROGRESS')
AND wo.status = #{status}
ORDER BY wo.create_time DESC
